#include <iomanip>

namespace {
    double clamp(double value, double lo, double hi) {
        if (value < lo) return lo;
        if (value > hi) return hi;
        return value;
    }

    double normalize(double value, double lo, double hi) {
        return (value - lo) / (hi - lo);
    }
