namespace Stats
{
    // Internal helper holds all state in static locals.
    // mode 0 = record a value, mode 1 = query (returns encoded via out-params).
    void update(bool query, int value, int& out_count, int& out_sum)
    {
        static int count = 0;
        static int sum   = 0;
        if (!query)
        {
            ++count;
            sum += value;
        }
        out_count = count;
        out_sum   = sum;
    }

    void record(int value)
    {
        int c{}, s{};
        update(false, value, c, s);
