    void print_stats()
    {
        int count{}, sum{};
        update(true, 0, count, sum);
        double average = static_cast<double>(sum) / count;
        std::cout << "Count: "   << count << '\n'
                  << "Sum: "     << sum   << '\n'
                  << "Average: " << std::fixed << std::setprecision(2)
                  << average    << '\n';
